import{_ as a,o,c as t,ag as s}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"LXC increase storage volume","description":"How to increase LXC container storage volume size using ZFS storage driver","frontmatter":{"description":"How to increase LXC container storage volume size using ZFS storage driver"},"headers":[],"relativePath":"software-engineering/containerisation/lxc-lxd/lxc-increase-storage-volume.md","filePath":"software-engineering/containerisation/lxc-lxd/lxc-increase-storage-volume.md"}'),i={name:"software-engineering/containerisation/lxc-lxd/lxc-increase-storage-volume.md"};function n(r,e,c,l,p,d){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="lxc-increase-storage-volume" tabindex="-1">LXC increase storage volume <a class="header-anchor" href="#lxc-increase-storage-volume" aria-label="Permalink to &quot;LXC increase storage volume&quot;">​</a></h1><p>The way I found to work the easiest is noted below:</p><p>LXD 3 or newer supports the creation of additional storage pools. Therefore, create an additional storage pool and then move the big container to the new storage pool.</p><p>Here is an example.</p><ol><li><p>Create an additional pool. Here we give 100GB of space.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lxc storage create secondpool zfs size=100GB</span></span></code></pre></div></li><li><p>Suppose the container is called <code>bigcontainer</code>. We move it with <code>lxc move</code>, specifying that it should be placed inside the new storage pool. During the move, we have to rename the container because we move within the same LXD server.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lxc move bigcontainer bigcontainer-moved --storage secondpool</span></span></code></pre></div></li></ol>',5)])])}const u=a(i,[["render",n]]);export{h as __pageData,u as default};
